// Filter only expired items (state = "on")
const expired = msg.payload.filter(e => e.state === "on");

msg.payload = expired.map(e => ({
    name: e.attributes.item_name,
    days_expired: Math.abs(e.attributes.days_until_expiry),
    storage: e.attributes.storage,
    category: e.attributes.category,
    barcode: e.attributes.barcode,
}));

msg.topic = `Found ${msg.payload.length} expired item(s)`;
return msg;

// Filter items expiring within the next 3 days (but not yet expired)
const expiringSoon = msg.payload.filter(e => {
    const days = e.attributes.days_until_expiry;
    return days !== null && days >= 0 && days <= 3;
});

msg.payload = expiringSoon.map(e => ({
    name: e.attributes.item_name,
    days_left: e.attributes.days_until_expiry,
    storage: e.attributes.storage,
    category: e.attributes.category,
    barcode: e.attributes.barcode,
}));

msg.topic = `Found ${msg.payload.length} item(s) expiring within 3 days`;
return msg;
